mersenne_twister_data = [random.random() for i in range(0, 2500)]

def convert_to_coords(data):
    xs = []
    ys = []
    
    for i in range(0, len(data)):
        if i % 2 == 0:
            xs.append(data[i])
        else:
            ys.append(data[i])
    return xs, ys


